body.script:
$("#passfield").on('input', function() {
  var passlength = $(this).val().length;
  if(passlength <= 0) {
    $("#passsave").prop('disabled', true);
    $("#passsave").addClass('disabled');
    $("#passshortnote").fadeOut();
  } else if (passlength > 0 && passlength < 8) {
    $("#passsave").prop('disabled', true);
    $("#passsave").addClass('disabled');
    $("#passshortnote").fadeIn();
  } else {
    $("#passsave").prop('disabled', false);
    $("#passsave").removeClass('disabled');
    $("#passshortnote").fadeOut();
  }
});

