var domain = location.host.substring(location.host.indexOf(".")+1);
var isLocal = new RegExp(domain);
var observer = new MutationObserver(function(mutations, observer) {
  observer.disconnect();
  $('a[target="_blank"]').each(function() {
    if(!isLocal.test($(this).attr('href'))) {
      $(this).attr('rel', 'nofollow me noopener noreferrer');
    }
  }).after(function() {
    observer.observe(document, {
      subtree: true,
      attributes: true
    })
  });
});
$(document).ready(function() {
  observer.observe(document, {
    subtree: true,
    attributes: true
  });
});

if(!("promoShown" in sessionStorage)) {
  var verticalBanner = false;

  $(document).ready(function() {
    if(window.innerWidth > 800) {
      $("#ad-horizontal").show();
      $("#ad-vertical").hide();
      verticalBanner = false;
    } else {
      $("#ad-horizontal").hide();
      $("#ad-vertical").show();
      verticalBanner = true;
    }    
  });

  $(window).on('resize orientationchange', function(){
    if(window.innerWidth > 800 && verticalBanner) {
      $("#ad-horizontal").show();
      $("#ad-vertical").hide();
      verticalBanner = false;
    } else if(window.innerWidth <= 800 && !verticalBanner) {
      $("#ad-horizontal").hide();
      $("#ad-vertical").show();
      verticalBanner = true;
    }
  });

  //$("#sched-overlay-ad").delay(5000).fadeIn("200");
}

var hasSchedule = false;
if(hasSchedule) {
  $("#sched-confirm-schedule-count").html(hasSchedule);
  $("#sched-confirm-schedule").slideDown();
} else {
  $("#sched-confirm-schedule").slideUp();
}

$("#sched-confirm-schedule a").click(function() {
  window.location.href = "";
  return false;
});

window.sentryOnLoad = function () {
  Sentry.init({
    integrations: [],

    tracesSampleRate: 0,
    replaysSessionSampleRate: 0,
    replaysOnErrorSampleRate: 0,
    beforeSend(event) {
      if (typeof event.tags !== 'undefined' && typeof event.tags.manualscope !== 'undefined' ) {
        return event;
      } else {
        return false;
      }
    },
  });
};
window.sentrySchedMessage = function (msg) {
  Sentry.forceLoad();
  Sentry.withScope((scope) => {
    scope.setTag("manualscope", "true");
    return Sentry.captureMessage(msg);
  });
};
window.sentrySchedException = function (ex) {
  Sentry.forceLoad();
  Sentry.withScope((scope) => {
    scope.setTag("manualscope", "true");
    return Sentry.captureException(ex);
  });
};

